CREATE OR REPLACE FUNCTION fpa_tel_lon_type_by_conno (as_conno char) RETURNS varchar AS $body$
DECLARE

ls_loan_type sc_lon_m_contract.loan_type%type;

BEGIN
  select  loan_type into STRICT ls_loan_type
  from    sc_lon_m_contract
  where   loan_contract_no = as_conno;
  if coalesce(ls_loan_type::text, '') = '' then ls_loan_type := ' ';end if;

  return ls_loan_type;
END;
$body$
